import './Tabs.scss';

import { classNames } from ':helpers/classnames';
import type { FC } from 'react';
import React, { useEffect, useRef, useState } from 'react';

import { Divider } from '../Divider';
import type { TabsProps } from './Tabs.types';
import { TabsScroller } from './TabsScroller';
import type { ScrollData } from './TabsScroller/TabsScroller.types';
import { useTabs } from './useTabs';
import { useTabsIndicator } from './useTabsIndicator';

export const Tabs: FC<TabsProps> = ({
	className,
	divider,
	align,
	children,
	selectedTabIndex,
	onChange,
	bodyClassName,
	...props
}) => {
	// TODO: выпилить этот хук после удаления устаревших табов
	useEffect(() => {
		if (divider || align) {
			console.warn(
				'[Tabs] Вы используете устареший пропс divider или align',
				'\nЧтобы убрать это ворнинг вы можете:',
				'\n1. Перевести компонент на новый синтаксис, он создан чтобы вам было проще:)',
				'\n о новом синтаксисе читайте на сторибуке (внутренняя сеть) https://ds-react.apps.mn-kp01.vimpelcom.ru/?path=/docs/components-tabs',
				'\n2. Импортировать компонент из папки deprecated и использовать старый синтаксис',
				'\n для этого замените import { Tab, Tabs } from "@beeline/design-tokens" на import { Tab, Tabs } from "@beeline/design-tokens/deprecated"',
			);
		}
		// хук должен вызываться единожды
		// eslint-disable-next-line react-hooks/exhaustive-deps
	}, []);

	const [scrollLeft, setScrollLeft] = useState(0);
	const headerRef = useRef(null);

	const {
		tabs,
		currentTabData: { tabBody, tabElement: currentTabElement, tabProps },
		prevTabData: { tabElement: previousTabElement },
	} = useTabs({
		onChange,
		selectedTabIndex,
		tabs: Array.isArray(children) ? children : [children],
	});

	const indicatorData = useTabsIndicator(currentTabElement, previousTabElement, headerRef.current, scrollLeft);

	const onScroll = ({ scrollLeft }: ScrollData): void => {
		setScrollLeft(scrollLeft);
	};

	return (
		<div data-testid="Tabs" className={classNames('dsb_tabs', className)} {...props}>
			<div className="dsb_tabs__header" ref={headerRef}>
				<TabsScroller onScroll={onScroll} className="dsb_tabs__header-tabs">
					{tabs}
				</TabsScroller>
				<Divider className="dsb_tabs__divider" />
				<div style={indicatorData} className="dsb_tabs__indicator" />
			</div>
			<div className={classNames('dsb_tabs__body', tabProps?.bodyClassName, bodyClassName)}>{tabBody}</div>
		</div>
	);
};
